import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { cartAPI } from '../api';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';

const CartContext = createContext(null);

export function CartProvider({ children }) {
  const { isAuthenticated } = useAuth();
  const [cart, setCart] = useState({ items: [], subtotal: 0, tax: 0, shipping: 0, total: 0, itemCount: 0 });
  const [loading, setLoading] = useState(false);

  const fetchCart = useCallback(async () => {
    if (!isAuthenticated) return;
    setLoading(true);
    try {
      const res = await cartAPI.get();
      setCart(res.data.data);
    } catch (e) {
      console.error('Cart fetch error:', e);
    } finally {
      setLoading(false);
    }
  }, [isAuthenticated]);

  useEffect(() => { fetchCart(); }, [fetchCart]);

  const addToCart = async (productId, quantity = 1, selectedSize, selectedColor) => {
    try {
      await cartAPI.add({ productId, quantity, selectedSize, selectedColor });
      toast.success('Added to cart!');
      fetchCart();
    } catch (e) {
      toast.error(e.response?.data?.message || 'Failed to add');
    }
  };

  const updateQuantity = async (itemId, quantity) => {
    try {
      await cartAPI.updateQty(itemId, quantity);
      fetchCart();
    } catch (e) {
      toast.error('Update failed');
    }
  };

  const removeItem = async (itemId) => {
    try {
      await cartAPI.remove(itemId);
      toast.success('Removed from cart');
      fetchCart();
    } catch (e) {
      toast.error('Remove failed');
    }
  };

  const clearCart = async () => {
    try {
      await cartAPI.clear();
      fetchCart();
    } catch (e) {
      toast.error('Clear failed');
    }
  };

  return (
    <CartContext.Provider value={{ cart, loading, fetchCart, addToCart, updateQuantity, removeItem, clearCart }}>
      {children}
    </CartContext.Provider>
  );
}

export const useCart = () => useContext(CartContext);
